mkdir -p /tmp/sv-65e49e6300814c09a6b73360edbf5fbd/typed-meta && cd /tmp/sv-65e49e6300814c09a6b73360edbf5fbd/typed-meta && dotnet new console --framework net11.0 -o . --force -n TypedMeta > /dev/null 2>&1 && cat > Program.cs << 'EOF'
using System;
using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1️⃣  Strongly-typed metadata retrieval — returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// 2️⃣  Probe without throwing — TryGetTypeInfo returns false when unavailable
//     Use an empty resolver so nothing is resolvable.
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // no resolvers → resolves nothing
};

bool found = empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"TryGetTypeInfo on empty resolver: found={found}, info is null={info is null}");

// Also show it succeeding:
bool found2 = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2);
Console.WriteLine($"TryGetTypeInfo on full resolver:  found={found2}, type={info2?.Type.Name}");

// A simple test type
public record Person(string Name, int Age);
EOF
cat Program.cs

